/**
 * DesktopCommandCenter — Electron-only control surface.
 * Shows system health, worker control, logs, kill switch, version/updates.
 * Gracefully hides when running in a web browser.
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import { useDesktop, useIsDesktop } from '../hooks/useDesktop';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';

const T = tokens.color;
const MONO = "'JetBrains Mono', ui-monospace, monospace";
const UI = "'Plus Jakarta Sans', Inter, system-ui, sans-serif";

// ─── Metric Card ─────────────────────────────────────────────
function Metric({ label, value, color = T.text, sub }) {
  return (
    <div style={{
      background: T.surface, borderRadius: 10, border: `1px solid ${T.border}`,
      padding: '12px 16px', flex: '1 1 140px', minWidth: 120,
    }}>
      <div style={{ fontSize: 10, color: T.textSecondary, marginBottom: 4, fontFamily: UI }}>{label}</div>
      <div style={{ fontSize: 20, fontWeight: 700, fontFamily: MONO, color }}>{value}</div>
      {sub && <div style={{ fontSize: 10, color: T.textSecondary, fontFamily: MONO, marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

// ─── Panel Card ──────────────────────────────────────────────
function Panel({ title, children, accent = T.blue }) {
  return (
    <div style={{
      background: T.surface, borderRadius: 12, border: `1px solid ${T.border}`,
      padding: '16px 20px', position: 'relative', overflow: 'hidden',
    }}>
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 2, background: accent }} />
      <div style={{ fontSize: 13, fontWeight: 700, color: T.textSecondary, marginBottom: 12, letterSpacing: 0.5 }}>
        {title}
      </div>
      {children}
    </div>
  );
}

// ─── Log Line ────────────────────────────────────────────────
function LogLine({ msg, idx }) {
  const isError = /error|fail|crash/i.test(msg);
  const isWarn = /warn|timeout|retry/i.test(msg);
  return (
    <div style={{
      fontSize: 11, fontFamily: MONO, padding: '2px 0',
      color: isError ? T.red : isWarn ? T.amber : T.textSecondary,
      borderBottom: `1px solid ${T.border}20`,
    }}>
      {msg}
    </div>
  );
}

export default function DesktopCommandCenter() {
  const desktop = useDesktop();
  const isDesktop = useIsDesktop();

  const [workerStatus, setWorkerStatus] = useState({ running: false, pid: null, jobsCompleted: 0, uptimeSeconds: 0 });
  const [systemInfo, setSystemInfo] = useState(null);
  const [apiHealth, setApiHealth] = useState(null);
  const [killSwitch, setKillSwitch] = useState(null);
  const [logs, setLogs] = useState([]);
  const [gridStats, setGridStats] = useState(null);
  const logsEndRef = useRef(null);

  // Poll worker status + API health
  useEffect(() => {
    const poll = async () => {
      if (desktop) {
        try { setWorkerStatus(await desktop.getWorkerStatus()); } catch {}
        if (!systemInfo) {
          try { setSystemInfo(await desktop.getSystemInfo()); } catch {}
        }
      }
      try {
        const health = await api('/control/health', { silent: true });
        setApiHealth(health);
        setKillSwitch(health?.kill || null);
      } catch {}
      try {
        const grid = await api('/grid/status', { silent: true });
        setGridStats(grid);
      } catch {}
    };
    poll();
    const id = setInterval(poll, 5000);
    return () => clearInterval(id);
  }, [desktop, systemInfo]);

  // Subscribe to worker logs
  useEffect(() => {
    if (!desktop) return;
    desktop.onWorkerLog((msg) => {
      setLogs(prev => {
        const next = [...prev, msg];
        return next.length > 200 ? next.slice(-200) : next;
      });
    });
  }, [desktop]);

  // Auto-scroll logs
  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const handleStartWorker = useCallback(async () => {
    if (desktop) {
      const result = await desktop.startWorker('compute');
      if (!result.success) setLogs(prev => [...prev, `[error] ${result.error}`]);
    }
  }, [desktop]);

  const handleStopWorker = useCallback(async () => {
    if (desktop) await desktop.stopWorker();
  }, [desktop]);

  const handleKillSwitch = useCallback(async (active) => {
    try {
      await api('/control/kill-switch', {
        method: 'POST',
        body: { active, reason: active ? 'Manual kill from desktop' : 'Resumed from desktop' },
      });
    } catch {}
  }, []);

  const canTrade = apiHealth?.can_trade;
  const apiLatency = apiHealth?.latency_ms;

  if (!isDesktop) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: T.textSecondary, fontFamily: UI }}>
        <h2 style={{ color: T.text, marginBottom: 12 }}>Desktop Command Center</h2>
        <p>This panel is available in the Aura Alpha desktop app.</p>
        <a href="https://auraalpha.cc/download" style={{ color: T.blue }}>Download Desktop App</a>
      </div>
    );
  }

  return (
    <div style={{ padding: '16px 20px', maxWidth: 1400, margin: '0 auto', fontFamily: UI }}>
      <h1 style={{ fontSize: 22, fontWeight: 800, color: T.text, marginBottom: 16 }}>
        Desktop Command Center
      </h1>

      {/* ── KPI Row ──────────────────────────────────── */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
        <Metric label="API Status" value={canTrade === true ? 'LIVE' : canTrade === false ? 'DOWN' : '...'} color={canTrade ? T.green : T.red} />
        <Metric label="Worker" value={workerStatus.running ? 'RUNNING' : 'STOPPED'} color={workerStatus.running ? T.green : T.textSecondary} sub={workerStatus.running ? `PID ${workerStatus.pid}` : ''} />
        <Metric label="Jobs Done" value={workerStatus.jobsCompleted?.toLocaleString() || '0'} color={T.blue} />
        <Metric label="Redis Queue" value={gridStats?.ready?.toLocaleString() || '—'} color={T.amber} sub={gridStats?.leased ? `${gridStats.leased} leased` : ''} />
        <Metric label="App Version" value={desktop?.version || '—'} color={T.purple} />
        <Metric label="Platform" value={desktop?.platform || '—'} color={T.textSecondary} />
      </div>

      {/* ── Main Grid ────────────────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 16 }}>

        {/* Worker Control */}
        <Panel title="WORKER CONTROL" accent={T.green}>
          <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
            <button onClick={handleStartWorker} disabled={workerStatus.running} style={{
              padding: '8px 16px', borderRadius: 6, border: 'none', cursor: 'pointer',
              background: workerStatus.running ? T.border : T.green, color: T.bg,
              fontWeight: 600, fontSize: 12, fontFamily: UI,
            }}>
              Start Worker
            </button>
            <button onClick={handleStopWorker} disabled={!workerStatus.running} style={{
              padding: '8px 16px', borderRadius: 6, border: 'none', cursor: 'pointer',
              background: !workerStatus.running ? T.border : T.red, color: T.bg,
              fontWeight: 600, fontSize: 12, fontFamily: UI,
            }}>
              Stop Worker
            </button>
          </div>
          {workerStatus.running && (
            <div style={{ fontSize: 11, fontFamily: MONO, color: T.textSecondary }}>
              <div>Uptime: {Math.floor(workerStatus.uptimeSeconds / 60)}m {workerStatus.uptimeSeconds % 60}s</div>
              <div>Jobs completed: {workerStatus.jobsCompleted}</div>
            </div>
          )}
        </Panel>

        {/* Kill Switch */}
        <Panel title="KILL SWITCH" accent={killSwitch?.active ? T.red : T.green}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 8 }}>
            <div style={{
              width: 16, height: 16, borderRadius: '50%',
              background: killSwitch?.active ? T.red : T.green,
              boxShadow: `0 0 8px ${killSwitch?.active ? T.red : T.green}40`,
            }} />
            <span style={{ fontSize: 14, fontWeight: 700, fontFamily: MONO, color: killSwitch?.active ? T.red : T.green }}>
              {killSwitch?.active ? 'KILL ACTIVE — ALL TRADING HALTED' : 'SYSTEMS NOMINAL'}
            </span>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={() => handleKillSwitch(true)} style={{
              padding: '6px 14px', borderRadius: 6, border: `1px solid ${T.red}`,
              background: 'transparent', color: T.red, cursor: 'pointer',
              fontWeight: 600, fontSize: 11, fontFamily: UI,
            }}>
              ACTIVATE KILL
            </button>
            <button onClick={() => handleKillSwitch(false)} style={{
              padding: '6px 14px', borderRadius: 6, border: `1px solid ${T.green}`,
              background: 'transparent', color: T.green, cursor: 'pointer',
              fontWeight: 600, fontSize: 11, fontFamily: UI,
            }}>
              RESUME TRADING
            </button>
          </div>
        </Panel>

        {/* System Info */}
        <Panel title="SYSTEM INFO" accent={T.cyan}>
          {systemInfo ? (
            <div style={{ fontSize: 11, fontFamily: MONO, color: T.textSecondary, lineHeight: 1.8 }}>
              <div>CPU: {systemInfo.cpuModel} ({systemInfo.cpuCount} cores)</div>
              <div>RAM: {systemInfo.freeRAM}GB free / {systemInfo.totalRAM}GB total</div>
              <div>Platform: {systemInfo.platform} {systemInfo.arch}</div>
              <div>Hostname: {systemInfo.hostname}</div>
            </div>
          ) : (
            <div style={{ fontSize: 11, color: T.textSecondary }}>Loading system info...</div>
          )}
        </Panel>

        {/* Redis Queue */}
        <Panel title="GRID QUEUE (REDIS)" accent={T.amber}>
          {gridStats ? (
            <div style={{ fontSize: 11, fontFamily: MONO, color: T.textSecondary, lineHeight: 1.8 }}>
              <div>Ready: <span style={{ color: T.amber }}>{gridStats.ready?.toLocaleString()}</span></div>
              <div>Leased: <span style={{ color: T.blue }}>{gridStats.leased?.toLocaleString()}</span></div>
              <div>Retry: <span style={{ color: T.purple }}>{gridStats.retry}</span></div>
              <div>Dead letter: <span style={{ color: T.red }}>{gridStats.dead}</span></div>
              <div>Memory: {gridStats.memory_mb} MB</div>
              <div>Workers active: {gridStats.workers_active}</div>
            </div>
          ) : (
            <div style={{ fontSize: 11, color: T.textSecondary }}>Connecting to Redis queue...</div>
          )}
        </Panel>
      </div>

      {/* ── Logs ─────────────────────────────────────── */}
      <Panel title="WORKER LOGS" accent={T.textSecondary}>
        <div style={{
          maxHeight: 250, overflow: 'auto', background: T.bg,
          borderRadius: 6, padding: '8px 12px',
        }}>
          {logs.length === 0 ? (
            <div style={{ fontSize: 11, color: T.textSecondary, fontFamily: MONO }}>
              No logs yet. Start the worker to see output.
            </div>
          ) : (
            logs.map((msg, i) => <LogLine key={i} msg={msg} idx={i} />)
          )}
          <div ref={logsEndRef} />
        </div>
      </Panel>
    </div>
  );
}
