/**
 * useDesktop — Detects Electron desktop shell and provides IPC bridge.
 *
 * When running inside Electron, window.auraDesktop is injected by preload.js.
 * This hook provides a safe interface that returns null on web.
 *
 * Usage:
 *   const desktop = useDesktop();
 *   if (desktop) {
 *     const status = await desktop.getWorkerStatus();
 *     desktop.startWorker('compute');
 *   }
 */

const isElectron = typeof window !== 'undefined' && !!window.auraDesktop;

export function useDesktop() {
  return isElectron ? window.auraDesktop : null;
}

export function useIsDesktop() {
  return isElectron;
}

export default useDesktop;
